program lipdecide;

uses
  SysUtils, Math;

const
  PI = 3.1415926535;

type
  POINTRANGE  = 1..100;
  LICRANGE    = 0..14;
  NPOINTS     = 2..100;
  NPTYPE      = 3..100;
  CONNECTORS  = (NOTUSED, ORR, ANDD);
  NUMQUADS    = 1..3;
  COORDINATE  = array[POINTRANGE] of real;
  CMATRIX     = array[LICRANGE, LICRANGE] of CONNECTORS;
  BMATRIX     = array[LICRANGE, LICRANGE] of boolean;
  VECTOR      = array[LICRANGE] of boolean;
  COMPTYPE    = (LT, EQ, GT);

var
  X          : COORDINATE;
  Y          : COORDINATE;
  NUMPOINTS  : integer;
  PARAMETERS : record
    LENGTH1  : real;
    RADIUS1  : real;
    EPSILON  : real;
    AREA1    : real;
    Q_PTS    : integer;
    QUADS    : integer;
    DIST     : real;
    N_PTS    : integer;
    K_PTS    : integer;
    A_PTS    : integer;
    B_PTS    : integer;
    C_PTS    : integer;
    D_PTS    : integer;
    E_PTS    : integer;
    F_PTS    : integer;
    G_PTS    : integer;
    LENGTH2  : real;
    RADIUS2  : real;
    AREA2    : real;
  end;
  LCM     : CMATRIX;
  PUM_DIAG: VECTOR;
  PUM     : BMATRIX;
  CMV     : VECTOR;
  FUV     : VECTOR;
  LAUNCH  : boolean;


function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

function DISTANCE(i, j: integer): real;
begin
  DISTANCE := sqrt(sqr(X[i] - X[j]) + sqr(Y[i] - Y[j]));
end;

function LIC0: boolean;
var
  i: integer;
begin
  LIC0 := false;
  if PARAMETERS.LENGTH1 < 0 then exit;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(DISTANCE(i, i + 1), PARAMETERS.LENGTH1) = GT then
    begin
      LIC0 := true;
      exit;
    end;
  end;
end;

function LIC1: boolean;
var
    i: integer;
    a, b, c, R: real;
begin
    LIC1 := false;
    if NUMPOINTS < 3 then exit;
    if PARAMETERS.RADIUS1 < 0 then exit;

    for i := 1 to NUMPOINTS - 2 do
    begin
        a := DISTANCE(i, i+1);
        b := DISTANCE(i+1, i+2);
        c := DISTANCE(i, i+2);

        if (REALCOMPARE(a,0) = EQ) and (REALCOMPARE(b,0) = EQ) and (REALCOMPARE(c,0)=EQ) then
        begin
            R := 0;
        end
        else if (REALCOMPARE(a, 0) = EQ) or (REALCOMPARE(b, 0) = EQ) or (REALCOMPARE(c, 0) = EQ) then
        begin
             if REALCOMPARE(a,b) = GT then R := a/2 else R := b/2;
             if REALCOMPARE(c,R*2) = GT then if REALCOMPARE(a,b) = GT then R := c/2 else R:= c/2;
        end
        else if REALCOMPARE(a*a+b*b,c*c) = EQ then
        begin
          R := c/2;
        end
        else if REALCOMPARE(b*b+c*c,a*a) = EQ then
        begin
          R := a/2;
        end
        else if REALCOMPARE(c*c+a*a,b*b) = EQ then
        begin
          R := b/2;
        end
        else
        begin
            R := (a * b * c) / sqrt(abs((a+b+c)*(b+c-a)*(c+a-b)*(a+b-c)));
        end;

        if REALCOMPARE(R, PARAMETERS.RADIUS1) = GT then
        begin
            LIC1 := TRUE;
            EXIT;
        end;
    end;
end;

function LIC2: boolean;
var
  i: integer;
  p1x, p1y, p2x, p2y, p3x, p3y: real;
  angle: real;
begin
  LIC2 := false;
  if NUMPOINTS < 3 then exit;
  if (PARAMETERS.EPSILON < 0) or (REALCOMPARE(PARAMETERS.EPSILON, PI) = GT) or (REALCOMPARE(PARAMETERS.EPSILON, PI) = EQ) then exit;

  for i := 1 to NUMPOINTS - 2 do
  begin
    p1x := X[i]; p1y := Y[i];
    p2x := X[i+1]; p2y := Y[i+1];
    p3x := X[i+2]; p3y := Y[i+2];

    if ((REALCOMPARE(p1x,p2x)=EQ) and (REALCOMPARE(p1y,p2y)=EQ)) or ((REALCOMPARE(p3x,p2x)=EQ) and (REALCOMPARE(p3y,p2y)=EQ)) then
      continue;

    angle := arctan2(p1y - p2y, p1x - p2x) - arctan2(p3y - p2y, p3x - p2x);

    if angle < 0 then angle := angle + 2*PI;
    if angle > PI then angle := 2*PI - angle;

    if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
       (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
    begin
      LIC2 := true;
      exit;
    end;
  end;
end;

function LIC3: boolean;
var
  i: integer;
  area: real;
begin
  LIC3 := false;
  if NUMPOINTS < 3 then exit;
  if PARAMETERS.AREA1 < 0 then exit;
  for i := 1 to NUMPOINTS - 2 do
  begin
    area := 0.5 * abs(X[i]*(Y[i+1]-Y[i+2]) + X[i+1]*(Y[i+2]-Y[i]) + X[i+2]*(Y[i]-Y[i+1]));
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      LIC3 := true;
      exit;
    end;
  end;
end;

function GetQuadrant(x, y: real): integer;
begin
    if (x >= 0) and (y >= 0) then exit(1);
    if (x < 0) and (y >= 0) then exit(2);
    if (x <= 0) and (y < 0) then exit(3);
    if (x > 0) and (y < 0) then exit(4);
    exit(0);
end;

function LIC4: boolean;
var
  i, j: integer;
  quads: array[1..4] of integer;
  quad_count: integer;
begin
  LIC4 := false;
  if (PARAMETERS.Q_PTS < 2) or (PARAMETERS.Q_PTS > NUMPOINTS) then exit;
  if (PARAMETERS.QUADS < 1) or (PARAMETERS.QUADS > 3) then exit;

  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    quad_count := 0;
    for j := 1 to 4 do quads[j] := 0;

    for j := 0 to PARAMETERS.Q_PTS - 1 do
    begin
       quads[GetQuadrant(X[i+j], Y[i+j])] := 1;
    end;

    for j := 1 to 4 do
        if quads[j] = 1 then
            inc(quad_count);

    if quad_count > PARAMETERS.QUADS then
    begin
      LIC4 := true;
      exit;
    end;
  end;
end;

function LIC5: boolean;
var
  i: integer;
begin
  LIC5 := false;
  if NUMPOINTS < 2 then exit;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i+1], X[i]) = LT then
    begin
      LIC5 := true;
      exit;
    end;
  end;
end;

function LIC6: boolean;
var
  i, j: integer;
  dist: real;
  p1x, p1y, p2x, p2y: real;
begin
  LIC6 := false;
  if NUMPOINTS < 3 then exit;
  if (PARAMETERS.N_PTS < 3) or (PARAMETERS.N_PTS > NUMPOINTS) then exit;
  if PARAMETERS.DIST < 0 then exit;

  for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    p1x := X[i]; p1y := Y[i];
    p2x := X[i + PARAMETERS.N_PTS - 1]; p2y := Y[i + PARAMETERS.N_PTS - 1];

    if (REALCOMPARE(p1x, p2x)=EQ) and (REALCOMPARE(p1y, p2y)=EQ) then
    begin
      for j := i + 1 to i + PARAMETERS.N_PTS - 2 do
      begin
        dist := DISTANCE(i,j);
        if REALCOMPARE(dist, PARAMETERS.DIST) = GT then
        begin
          LIC6 := true;
          exit;
        end;
      end;
    end
    else
    begin
      for j := i + 1 to i + PARAMETERS.N_PTS - 2 do
      begin
        dist := abs((p2x - p1x) * (p1y - Y[j]) - (p1x - X[j]) * (p2y - p1y)) / sqrt(sqr(p2x - p1x) + sqr(p2y - p1y));
        if REALCOMPARE(dist, PARAMETERS.DIST) = GT then
        begin
          LIC6 := true;
          exit;
        end;
      end;
    end;
  end;
end;

function LIC7: boolean;
var
  i: integer;
begin
  LIC7 := false;
  if NUMPOINTS < 3 then exit;
  if (PARAMETERS.K_PTS < 1) or (PARAMETERS.K_PTS > NUMPOINTS - 2) then exit;

