procedure DECIDE;
var
  i, j: integer;
  all_true: boolean;
begin
  CMV[0] := LIC0;
  CMV[1] := LIC1;
  CMV[2] := LIC2;
  CMV[3] := LIC3;
  CMV[4] := LIC4;
  CMV[5] := LIC5;
  CMV[6] := LIC6;
  CMV[7] := LIC7;
  CMV[8] := LIC8;
  CMV[9] := LIC9;
  CMV[10] := LIC10;
  CMV[11] := LIC11;
  CMV[12] := LIC12;
  CMV[13] := LIC13;
  CMV[14] := LIC14;

  for i := 0 to 14 do
  begin
    for j := i to 14 do
    begin
        case LCM[i, j] of
          NOTUSED: begin PUM[i, j] := true; PUM[j,i] := true; end;
          ORR: begin PUM[i, j] := CMV[i] or CMV[j]; PUM[j,i] := CMV[i] or CMV[j]; end;
          ANDD: begin PUM[i, j] := CMV[i] and CMV[j]; PUM[j,i] := CMV[i] and CMV[j]; end;
        end;
    end;
  end;

  for i := 0 to 14 do
  begin
    if not PUM_DIAG[i] then
      FUV[i] := true
    else
    begin
      all_true := true;
      for j := 0 to 14 do
      begin
        if i <> j then
        begin
          if not PUM[i,j] then
          begin
              all_true := false;
              break;
          end;
        end;
      end;
      FUV[i] := all_true;
    end;
  end;

  LAUNCH := true;
  for i := 0 to 14 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      break;
    end;
  end;
end;

var
  InputString: ansistring;
  ParsePos: integer;

procedure SkipWhitespace;
begin
  while (ParsePos <= Length(InputString)) and (InputString[ParsePos] in [' ', #9, #10, #13]) do
    Inc(ParsePos);
end;

function ParseString: ansistring;
var
  EndPos: integer;
  res: ansistring;
begin
  res := '';
  SkipWhitespace;
  if InputString[ParsePos] = '"' then
  begin
    Inc(ParsePos);
    EndPos := ParsePos;
    while (EndPos <= Length(InputString)) and (InputString[EndPos] <> '"') do
      Inc(EndPos);
    res := Copy(InputString, ParsePos, EndPos - ParsePos);
    ParsePos := EndPos + 1;
  end;
  exit(res);
end;

function ParseValue: ansistring;
var
  EndPos: integer;
  c: char;
  res: ansistring;
begin
    res := '';
    SkipWhitespace;
    EndPos := ParsePos;
    while (EndPos <= Length(InputString)) do
    begin
        c := InputString[EndPos];
        if (c = ' ') or (c = ',') or (c = '}') or (c=']') then
            break;
        inc(EndPos);
    end;
    res := Copy(InputString, ParsePos, EndPos - ParsePos);
    ParsePos := EndPos;
    exit(res);
end;

procedure ParseInput;
var
  i, j: integer;
  key: ansistring;
  val_str: ansistring;
begin
    InputString := '';
    while not eof do
    begin
        readln(val_str);
        InputString := InputString + val_str;
    end;

  ParsePos := 1;
  while ParsePos <= Length(InputString) do
  begin
    SkipWhitespace;
    if InputString[ParsePos] = '"' then
    begin
      key := ParseString;
      SkipWhitespace;
      if InputString[ParsePos] = ':' then Inc(ParsePos);

      if key = 'numpoints' then NUMPOINTS := StrToInt(ParseValue)
      else if key = 'x' then
      begin
        SkipWhitespace;
        if InputString[ParsePos] = '[' then Inc(ParsePos);
        for i := 1 to NUMPOINTS do
        begin
          X[i] := StrToFloat(ParseValue);
          SkipWhitespace;
          if InputString[ParsePos] = ',' then Inc(ParsePos);
        end;
        SkipWhitespace;
        if InputString[ParsePos] = ']' then Inc(ParsePos);
      end
      else if key = 'y' then
      begin
        SkipWhitespace;
        if InputString[ParsePos] = '[' then Inc(ParsePos);
        for i := 1 to NUMPOINTS do
        begin
          Y[i] := StrToFloat(ParseValue);
          SkipWhitespace;
          if InputString[ParsePos] = ',' then Inc(ParsePos);
        end;
        SkipWhitespace;
        if InputString[ParsePos] = ']' then Inc(ParsePos);
      end
      else if key = 'parameters' then
      begin
        while InputString[ParsePos] <> '}' do
        begin
            key := ParseString;
            SkipWhitespace;
            if InputString[ParsePos] = ':' then Inc(ParsePos);
            val_str := ParseValue;

            if key = 'LENGTH1' then PARAMETERS.LENGTH1 := StrToFloat(val_str)
            else if key = 'RADIUS1' then PARAMETERS.RADIUS1 := StrToFloat(val_str)
            else if key = 'EPSILON' then PARAMETERS.EPSILON := StrToFloat(val_str)
            else if key = 'AREA1' then PARAMETERS.AREA1 := StrToFloat(val_str)
            else if key = 'Q_PTS' then PARAMETERS.Q_PTS := StrToInt(val_str)
            else if key = 'QUADS' then PARAMETERS.QUADS := StrToInt(val_str)
            else if key = 'DIST' then PARAMETERS.DIST := StrToFloat(val_str)
            else if key = 'N_PTS' then PARAMETERS.N_PTS := StrToInt(val_str)
            else if key = 'K_PTS' then PARAMETERS.K_PTS := StrToInt(val_str)
            else if key = 'A_PTS' then PARAMETERS.A_PTS := StrToInt(val_str)
            else if key = 'B_PTS' then PARAMETERS.B_PTS := StrToInt(val_str)
            else if key = 'C_PTS' then PARAMETERS.C_PTS := StrToInt(val_str)
            else if key = 'D_PTS' then PARAMETERS.D_PTS := StrToInt(val_str)
            else if key = 'E_PTS' then PARAMETERS.E_PTS := StrToInt(val_str)
            else if key = 'F_PTS' then PARAMETERS.F_PTS := StrToInt(val_str)
            else if key = 'G_PTS' then PARAMETERS.G_PTS := StrToInt(val_str)
            else if key = 'LENGTH2' then PARAMETERS.LENGTH2 := StrToFloat(val_str)
            else if key = 'RADIUS2' then PARAMETERS.RADIUS2 := StrToFloat(val_str)
            else if key = 'AREA2' then PARAMETERS.AREA2 := StrToFloat(val_str);

            SkipWhitespace;
            if InputString[ParsePos] = ',' then Inc(ParsePos);
        end;
      end
      else if key = 'lcm' then
      begin
        SkipWhitespace;
        if InputString[ParsePos] = '[' then Inc(ParsePos);
        for i := 0 to 14 do
        begin
          SkipWhitespace;
          if InputString[ParsePos] = '[' then Inc(ParsePos);
          for j := 0 to 14 do
          begin
            val_str := ParseString;
            if val_str = 'NOTUSED' then LCM[i,j] := NOTUSED
            else if val_str = 'ORR' then LCM[i,j] := ORR
            else if val_str = 'ANDD' then LCM[i,j] := ANDD;
            SkipWhitespace;
            if InputString[ParsePos] = ',' then Inc(ParsePos);
          end;
          SkipWhitespace;
          if InputString[ParsePos] = ']' then Inc(ParsePos);
          SkipWhitespace;
          if InputString[ParsePos] = ',' then Inc(ParsePos);
        end;
        SkipWhitespace;
        if InputString[ParsePos] = ']' then Inc(ParsePos);
      end
      else if key = 'pum_diag' then
       begin
        SkipWhitespace;
        if InputString[ParsePos] = '[' then Inc(ParsePos);
        for i := 0 to 14 do
        begin
          val_str := ParseValue;
          if val_str = 'true' then PUM_DIAG[i] := true
          else PUM_DIAG[i] := false;
          SkipWhitespace;
          if InputString[ParsePos] = ',' then Inc(ParsePos);
        end;
        SkipWhitespace;
        if InputString[ParsePos] = ']' then Inc(ParsePos);
      end;
    end
    else
        Inc(ParsePos);
  end;
end;

procedure WriteOutput;
var
  i, j: integer;
begin
  write('{"cmv":[');
  for i := 0 to 14 do
  begin
    if CMV[i] then write('true') else write('false');
    if i < 14 then write(',');
  end;
  write('],"pum":[');
  for i := 0 to 14 do
  begin
    write('[');
    for j := 0 to 14 do
    begin
      if PUM[i,j] then write('true') else write('false');
      if j < 14 then write(',');
    end;
    write(']');
    if i < 14 then write(',');
  end;
  write('],"fuv":[');
  for i := 0 to 14 do
  begin
    if FUV[i] then write('true') else write('false');
    if i < 14 then write(',');
  end;
  write('],"launch":');
  if LAUNCH then writeln('true}') else writeln('false}');
end;

begin
  ParseInput;
  DECIDE;
  WriteOutput;
end.
